var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으, 으윽…….","JPN":"う、ううっ……","ENG":"N-ngh...","TWN":"呃，呃呃……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"정신이 듭니까, 휴먼?","JPN":"気がつきましたか？　ヒューマン。","ENG":"Are you awake, human?","TWN":"你醒了，人類？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"호라이즌 씨……?","JPN":"ホライズンさん……？","ENG":"Horizon...?","TWN":"地平線……？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"가, 가야 해요. 루이제 아주머니가…… ","JPN":"い、行かなきゃ。ルイーゼおばさんが…… ","ENG":"W-we have to get going. Madam Schneider is–","TWN":"我…我要走了，露易絲伯母她……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아윽!?","JPN":"あうっ！？","ENG":"Augh?!","TWN":"呃呃？！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"움직이지 마십시오. 늑골 골절을 비롯, 부상이 심각합니다.","JPN":"動かないでください。肋骨骨折を始め、ひどい怪我です。","ENG":"Do not move. You are severely injured with a rib fracture.","TWN":"不要動，你的肋骨斷了，其他部位也受到重傷。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"튕겨나간 방향의 외벽이 유리창이 아니라 일반적인 장갑재였다면 내장 파열로 즉사였습니다.","JPN":"弾き飛ばされた方向の外壁がガラス窓ではなく一般的な装甲材だったなら、内臓破裂で即死していたのでしょう。","ENG":"If you had hit armor instead of that glass window, you would have died instantly from internal trauma.","TWN":"如果你彈出去的時候撞到的是鋼鐵而不是玻璃，你就會立刻因內臟破裂而死去。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요. 제가 더 서둘렀으면…… 약골만 아니었으면……","JPN":"すみません。私がもっと急いでたら……弱くなかったら……","ENG":"I'm sorry. If I had been quicker... and if I weren't such a weakling...","TWN":"對不起。如果我動作再快一些……如果我再強一些……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"자책하지 않아도 괜찮습니다. 휴먼.","JPN":"自分を責める必要はありません。ヒューマン。","ENG":"There is no need for self-torture, human.","TWN":"不用自責，人類。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"그 그림자가 말하더군요.","JPN":"あのシャドウがこう言っていました。","ENG":"This is what that Shadow said.","TWN":"那個暗影有說，"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자신의 곡을 두 번이나 들었는데, 두 번 모두 영향을 받지 않았다고.","JPN":"自分の曲を二度も聞いているのに、一度も影響を受けなかったと。","ENG":"Both times she listened to Plaga's song, she wasn't affected.","TWN":"明明聽到二次她的曲子，卻沒有受到影響。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"설마 그 곡이… 코러스에서 연주되었던 곡인가요?","JPN":"まさかあの曲が……コーラスから演奏された曲なんですか？","ENG":"When you say \\"song\\"... do you mean the one performed on Chorus?","TWN":"那首曲子……難道是Chorus上演奏的那一首？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 이유는 둘 중 하나입니다.","JPN":"はい。理由は次のどちらかです。","ENG":"Correct. It is either of these two reasons.","TWN":"是。理由有二個。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 곡에 휘둘리지 않을 만큼 의지가 강하거나.","JPN":"そのような曲に振り回されないほどに強い意志を持っているか。","ENG":"One: Her will is strong enough not to be affected by the song.","TWN":"一個是因為意志力足夠強大，不會受到演奏的影響。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"스스로 이미 죽음을 받아들였거나.","JPN":"すでに死を受け入れているか。","ENG":"Or two: She had already accepted death.","TWN":"另一個是因為她已經接受死亡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니가……. 죽음을…….","JPN":"おばさんが……死んで……","ENG":"Madam Schneider... accepted death...?","TWN":"伯母……接受死亡……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"호라이즌 씨, 저건……?","JPN":"ホライズンさん、あれは……？","ENG":"Horizon, what's that...?","TWN":"地平線，那是……？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"앙코르도 외치지 않았는데 공연을 속행하는군요.","JPN":"アンコールもしていないのに、公演を続行するようです。","ENG":"It seems they are continuing with their performance despite the audience not requesting an encore.","TWN":"明明沒有喊安可，表演卻還要繼續嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"우선 수송기까지 이동하겠습니다. 잘 붙잡으십시오.","JPN":"まずは輸送船まで移動します。しっかりと掴まってください。","ENG":"I will first move you to the transport aircraft. Hold on to me.","TWN":"先回到運輸機吧，抓好。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"맙소사…! 아까 그 침식체야! 하나 더 숨어 있었나 봐요!","JPN":"そんな……！　さっきの侵食体！　もう一匹隠れていたみたいです！","ENG":"Goodness…! It's that C.O. from earlier! Looks like another one was hiding!","TWN":"天啊…！是剛剛那個侵蝕體！竟然還藏著一個！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아니다. 저것은….","JPN":"違う。あれは……","ENG":"No. That is...","TWN":"不，那是……"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"왜 그러지? 무언가 느껴지나?","JPN":"どうした？　何か感じるのか？","ENG":"What is it? Do you sense anything?","TWN":"怎麼了？你感受到什麼？"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"뒤틀려 있지만… 저 괴물에게서 카르멘과 같은 기척이 느껴진다.","JPN":"ねじ曲がっているが……あの怪物から、カルメンと同じ気配が感じられる。","ENG":"It is twisted, but... I feel Carmen's presence within that monster.","TWN":"雖然極度扭曲……但那只怪物確實在散發著卡門的氣息。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"카르멘이라면……. 그 계획이란 건 결국 실패했나 보군.","JPN":"カルメンなら……計画とやらが失敗したということだな。","ENG":"Carmen...? That must mean that her plan ended in failure.","TWN":"卡門……這麼說，她的計畫還是失敗了。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"단원들도 증원하였는가.","JPN":"団員たちも増員したか。","ENG":"Did they also increase their members' numbers?","TWN":"團員有增加嗎？"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"저들은 수가 많아질수록 서로 공명한다. 주의하라, 황금가지의 전사여.","JPN":"やつらは数が多くなるほど、お互いに共鳴し合う。注意せよ、金の枝の戦士よ。","ENG":"The more of them there are, the more they will resonate with each other. Be careful, warrior of the Golden Branch.","TWN":"他們之間的共鳴會隨著數量增加而加強，金枝戰士，你要小心。"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"음. 새겨듣도록 하지.","JPN":"うむ。肝に銘じておこう。","ENG":"Right. I will keep that in mind.","TWN":"嗯，我會記住。"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"함선 내부에서 마에스트로의 신호가 소실되었습니다.","JPN":"艦船内部からマエストロの信号が消失しました。","ENG":"Maestra's signal from within the ship is lost.","TWN":"艦船內已經感應不到指揮家的訊號。"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L2_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"지체하는 동안 무슨 일을 저지를지 미지수입니다.","JPN":"時間が経てば何が起こるか未知数です。","ENG":"It is unknown what she will do while we are held up.","TWN":"這段期間，無法確定他們會做出什麼事。"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……서둘러야겠군.","JPN":"……急がねばな。","ENG":"...Then we must hurry.","TWN":"……要抓緊時間。"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"가자, 허밋!","JPN":"行くぞ、ハーミット！","ENG":"Giddy up, Hermit!","TWN":"走吧，赫米特！"},"stage":{"bg":"ROOFTOP","bgm":"UI_FIERCE_SOPRANO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};